internal fun getPngSizeOrNull(bytes: ByteArray): Pair<Int, Int>? {
    if (bytes.size < 24) return null
    if (
        int32(bytes[0], bytes[1], bytes[2], bytes[3]) == 0x8950_4E47u &&
        int32(bytes[4], bytes[5], bytes[6], bytes[7]) == 0x0D0A_1A0Au
    ) {
        val width = int32(bytes[16], bytes[17], bytes[18], bytes[19])
        val height = int32(bytes[20], bytes[21], bytes[22], bytes[23])
        return width.toInt() to height.toInt()
    }
    return null
}

internal fun String?.toNonNegativeInt(defaultValue: Int): Int {
    try {
        val value = this?.toLong() ?: return defaultValue
        return when {
            value > Int.MAX_VALUE -> Int.MAX_VALUE
            value < 0 -> 0
            else -> value.toInt()
        }
    } catch (_: NumberFormatException) {
        return defaultValue
    }
}

override fun display(level: Level, msg: MESSAGE) {
    when (level) {
        Level.DEBUG -> Log.d(KOIN_TAG, msg)
        Level.INFO -> Log.i(KOIN_TAG, msg)
        Level.WARNING -> Log.w(KOIN_TAG, msg)
        Level.ERROR -> Log.e(KOIN_TAG, msg)
        else -> Log.e(KOIN_TAG, msg)
    }
}

