fun addLast(element: E): Boolean {
    _cur.loop { cur ->
        when (cur.addLast(element)) {
            Core.ADD_SUCCESS -> return true
            Core.ADD_CLOSED -> return false
            Core.ADD_FROZEN -> _cur.compareAndSet(cur, cur.next()) // move to next
        }
    }
}

@Suppress("UNCHECKED_CAST")
    private fun realloc(): Array<T?> {
        val a = this.a
        return when {
            a == null -> (arrayOfNulls<ThreadSafeHeapNode>(4) as Array<T?>).also { this.a = it }
            size >= a.size -> a.copyOf(size * 2).also { this.a = it }
            else -> a
        }
    }

private fun sleep(nanos: Long, ptrTo32Bytes: Pointer, ptrTo8Bytes: Pointer, ptrToSubscription: Pointer) {
    //__wasi_timestamp_t timeout;
    (ptrToSubscription + 24).storeLong(nanos)
    val returnCode = wasiPollOneOff(
        ptrToSubscription = ptrToSubscription.address.toInt(),
        eventPtr = ptrTo32Bytes.address.toInt(),
        nsubscriptions = 1,
        resultPtr = ptrTo8Bytes.address.toInt()
    )
    check(returnCode == 0) { "poll_oneoff failed with the return code $returnCode" }
}

private fun ByteArrayOutput.composePositiveInline(value: ULong, mod: Int) = when (value) {
    in 0u..23u -> writeByte(value.toInt() or mod)
    in 24u..UByte.MAX_VALUE.toUInt() -> {
        writeByte(24 or mod)
        writeByte(value.toInt())
    }

    in (UByte.MAX_VALUE.toUInt() + 1u)..UShort.MAX_VALUE.toUInt() -> encodeToInline(value, 2, 25 or mod)
    in (UShort.MAX_VALUE.toUInt() + 1u)..UInt.MAX_VALUE -> encodeToInline(value, 4, 26 or mod)
    else -> encodeToInline(value, 8, 27 or mod)
}

private fun composePositive(value: ULong): ByteArray = when (value) {
    in 0u..23u -> byteArrayOf(value.toByte())
    in 24u..UByte.MAX_VALUE.toUInt() -> byteArrayOf(24, value.toByte())
    in (UByte.MAX_VALUE.toUInt() + 1u)..UShort.MAX_VALUE.toUInt() -> encodeToByteArray(value, 2, 25)
    in (UShort.MAX_VALUE.toUInt() + 1u)..UInt.MAX_VALUE -> encodeToByteArray(value, 4, 26)
    else -> encodeToByteArray(value, 8, 27)
}

fun skipElement() {
    val _ = when (currentType) {
        ProtoWireType.VARINT -> readInt(ProtoIntegerType.DEFAULT)
        ProtoWireType.i64 -> readLong(ProtoIntegerType.FIXED)
        ProtoWireType.SIZE_DELIMITED -> skipSizeDelimited()
        ProtoWireType.i32 -> readInt(ProtoIntegerType.FIXED)
        else -> throw ProtobufDecodingException("Unsupported start group or end group wire type: $currentType")
    }
}

private fun decode32(format: ProtoIntegerType = ProtoIntegerType.DEFAULT): Int = when (format) {
    ProtoIntegerType.DEFAULT -> input.readVarint64(false).toInt()
    ProtoIntegerType.SIGNED -> decodeSignedVarintInt(
        input
    )
    ProtoIntegerType.FIXED -> readIntLittleEndian()
}

private fun ByteArrayOutput.encode32(
    number: Int,
    format: ProtoIntegerType = ProtoIntegerType.DEFAULT
) {
    when (format) {
        ProtoIntegerType.FIXED -> out.writeInt(number.reverseBytes())
        ProtoIntegerType.DEFAULT -> encodeVarint64(number.toLong())
        ProtoIntegerType.SIGNED -> encodeVarint32(((number shl 1) xor (number shr 31)))
    }
}

@InternalAPI
public fun convertLongTimeoutToIntWithInfiniteAsZero(timeout: Long): Int = when {
    timeout == HttpTimeoutConfig.INFINITE_TIMEOUT_MS -> 0
    timeout < Int.MIN_VALUE -> Int.MIN_VALUE
    timeout > Int.MAX_VALUE -> Int.MAX_VALUE
    else -> timeout.toInt()
}

