            digest.usePinned { digestPinned ->
                CC_SHA1(inputPinned.addressOf(0), this.size.convert(), digestPinned.addressOf(0))
            }
        }
        return digest.toByteArray().toNSData().base64EncodedStringWithOptions(0u)
    }
